const ERR_NON_ADJ = 'Cannot connect non-adjacent islands';
const ERR_MAX2 = 'Max 2 bridges per pair';
const ERR_EXCEED = 'Island would exceed its number';
const ERR_CROSS = 'Bridges would cross';

export function canonicalKey(from, to) {
  const a = { x: from.x, y: from.y };
  const b = { x: to.x, y: to.y };
  const first = a.x < b.x || (a.x === b.x && a.y <= b.y) ? a : b;
  const second = first === a ? b : a;
  return `${first.x},${first.y},${second.x},${second.y}`;
}

export function parseKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map((n) => Number(n));
  return { x1, y1, x2, y2 };
}

function islandAt(islands, x, y) {
  return islands.find((i) => i.x === x && i.y === y) || null;
}

export function areAdjacent(islands, a, b) {
  if (!a || !b) return false;
  if (a.x !== b.x && a.y !== b.y) return false;

  if (a.x === b.x) {
    const yMin = Math.min(a.y, b.y);
    const yMax = Math.max(a.y, b.y);
    for (let y = yMin + 1; y <= yMax - 1; y++) {
      if (islandAt(islands, a.x, y)) return false;
    }
    return true;
  }

  const xMin = Math.min(a.x, b.x);
  const xMax = Math.max(a.x, b.x);
  for (let x = xMin + 1; x <= xMax - 1; x++) {
    if (islandAt(islands, x, a.y)) return false;
  }
  return true;
}

function segmentsFromBridges(bridges) {
  const segs = [];
  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const vertical = x1 === x2;
    segs.push({ x1, y1, x2, y2, vertical, key });
  }
  return segs;
}

function wouldCrossExisting(bridges, from, to) {
  const newVertical = from.x === to.x;
  const segs = segmentsFromBridges(bridges);
  const nx1 = from.x;
  const ny1 = from.y;
  const nx2 = to.x;
  const ny2 = to.y;
  const nMinX = Math.min(nx1, nx2);
  const nMaxX = Math.max(nx1, nx2);
  const nMinY = Math.min(ny1, ny2);
  const nMaxY = Math.max(ny1, ny2);

  for (const s of segs) {
    if (s.vertical === newVertical) continue;

    if (newVertical) {
      const vx = nx1;
      const vyMin = nMinY;
      const vyMax = nMaxY;
      const hy = s.y1;
      const hxMin = Math.min(s.x1, s.x2);
      const hxMax = Math.max(s.x1, s.x2);

      const crossX = vx;
      const crossY = hy;

      const withinV = crossY > vyMin && crossY < vyMax;
      const withinH = crossX > hxMin && crossX < hxMax;
      if (withinV && withinH) return true;
    } else {
      const hy = ny1;
      const hxMin = nMinX;
      const hxMax = nMaxX;
      const vx = s.x1;
      const vyMin = Math.min(s.y1, s.y2);
      const vyMax = Math.max(s.y1, s.y2);

      const crossX = vx;
      const crossY = hy;

      const withinH = crossX > hxMin && crossX < hxMax;
      const withinV = crossY > vyMin && crossY < vyMax;
      if (withinH && withinV) return true;
    }
  }
  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const i of islands) counts.set(i.id, 0);

  const byCoord = new Map(islands.map((i) => [`${i.x},${i.y}`, i]));
  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const i1 = byCoord.get(`${x1},${y1}`);
    const i2 = byCoord.get(`${x2},${y2}`);
    if (!i1 || !i2) continue;
    counts.set(i1.id, (counts.get(i1.id) || 0) + n);
    counts.set(i2.id, (counts.get(i2.id) || 0) + n);
  }
  return counts;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!areAdjacent(islands, from, to)) {
    return { valid: false, error: ERR_NON_ADJ };
  }

  const key = canonicalKey(from, to);
  const existing = bridges.get(key) || 0;
  const next = existing + delta;
  if (next < 0) return { valid: true, error: null };
  if (next > 2) return { valid: false, error: ERR_MAX2 };

  if (delta > 0) {
    if (wouldCrossExisting(bridges, from, to)) {
      return { valid: false, error: ERR_CROSS };
    }
  }

  const counts = computeCurrentCounts(islands, bridges);
  const fromIsland = islands.find((i) => i.x === from.x && i.y === from.y) || from;
  const toIsland = islands.find((i) => i.x === to.x && i.y === to.y) || to;

  const fromCount = counts.get(fromIsland.id) || 0;
  const toCount = counts.get(toIsland.id) || 0;

  if (delta > 0) {
    if (fromCount + delta > fromIsland.value || toCount + delta > toIsland.value) {
      return { valid: false, error: ERR_EXCEED };
    }
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length <= 1) return true;
  const byCoord = new Map(islands.map((i) => [`${i.x},${i.y}`, i]));

  const adj = new Map(islands.map((i) => [i.id, new Set()]));
  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = byCoord.get(`${x1},${y1}`);
    const b = byCoord.get(`${x2},${y2}`);
    if (!a || !b) continue;
    adj.get(a.id).add(b.id);
    adj.get(b.id).add(a.id);
  }

  const start = islands[0].id;
  const seen = new Set([start]);
  const queue = [start];
  while (queue.length) {
    const cur = queue.shift();
    for (const nb of adj.get(cur) || []) {
      if (!seen.has(nb)) {
        seen.add(nb);
        queue.push(nb);
      }
    }
  }
  return seen.size === islands.length;
}

export function bridgesCross(bridges) {
  const segs = segmentsFromBridges(bridges);
  for (let i = 0; i < segs.length; i++) {
    for (let j = i + 1; j < segs.length; j++) {
      const a = segs[i];
      const b = segs[j];
      if (a.vertical === b.vertical) continue;
      const v = a.vertical ? a : b;
      const h = a.vertical ? b : a;
      const vx = v.x1;
      const vyMin = Math.min(v.y1, v.y2);
      const vyMax = Math.max(v.y1, v.y2);
      const hy = h.y1;
      const hxMin = Math.min(h.x1, h.x2);
      const hxMax = Math.max(h.x1, h.x2);
      const withinV = hy > vyMin && hy < vyMax;
      const withinH = vx > hxMin && vx < hxMax;
      if (withinV && withinH) return true;
    }
  }
  return false;
}

export function isVictory(islands, bridges) {
  const counts = computeCurrentCounts(islands, bridges);
  for (const i of islands) {
    if ((counts.get(i.id) || 0) !== i.value) return false;
  }
  if (bridgesCross(bridges)) return false;
  if (!checkConnectivity(islands, bridges)) return false;
  return true;
}

export const ERROR_TEXTS = {
  ERR_NON_ADJ,
  ERR_MAX2,
  ERR_EXCEED,
  ERR_CROSS
};
