    if (fromCount + delta > fromIsland.value || toCount + delta > toIsland.value) {
      return { valid: false, error: ERR_EXCEED };
    }
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length <= 1) return true;
  const byCoord = new Map(islands.map((i) => [`${i.x},${i.y}`, i]));

  const adj = new Map(islands.map((i) => [i.id, new Set()]));
  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = byCoord.get(`${x1},${y1}`);
    const b = byCoord.get(`${x2},${y2}`);
    if (!a || !b) continue;
    adj.get(a.id).add(b.id);
    adj.get(b.id).add(a.id);
  }

  const start = islands[0].id;
  const seen = new Set([start]);
  const queue = [start];
  while (queue.length) {
    const cur = queue.shift();
    for (const nb of adj.get(cur) || []) {
      if (!seen.has(nb)) {
        seen.add(nb);
        queue.push(nb);
      }
    }
  }
  return seen.size === islands.length;
}

export function bridgesCross(bridges) {
  const segs = segmentsFromBridges(bridges);
  for (let i = 0; i < segs.length; i++) {
    for (let j = i + 1; j < segs.length; j++) {
      const a = segs[i];
      const b = segs[j];
      if (a.vertical === b.vertical) continue;
      const v = a.vertical ? a : b;
      const h = a.vertical ? b : a;
      const vx = v.x1;
      const vyMin = Math.min(v.y1, v.y2);
      const vyMax = Math.max(v.y1, v.y2);
      const hy = h.y1;
      const hxMin = Math.min(h.x1, h.x2);
      const hxMax = Math.max(h.x1, h.x2);
      const withinV = hy > vyMin && hy < vyMax;
      const withinH = vx > hxMin && vx < hxMax;
      if (withinV && withinH) return true;
    }
  }
  return false;
}

export function isVictory(islands, bridges) {
  const counts = computeCurrentCounts(islands, bridges);
  for (const i of islands) {
    if ((counts.get(i.id) || 0) !== i.value) return false;
  }
  if (bridgesCross(bridges)) return false;
  if (!checkConnectivity(islands, bridges)) return false;
  return true;
}

export const ERROR_TEXTS = {
  ERR_NON_ADJ,
  ERR_MAX2,
  ERR_EXCEED,
  ERR_CROSS
};
