import React, { useEffect, useMemo, useRef, useState } from 'react';
import { PUZZLES } from './data/puzzles.js';
import {
  areAdjacent,
  canonicalKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory
} from './utils/hashiLogic.js';

const GRID_PX = 40;
const SVG_W = 800;
const SVG_H = 600;
const ISLAND_R = 16;

function islandPixel(i) {
  return { px: i.x * GRID_PX, py: i.y * GRID_PX };
}

function keyToEndpoints(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

function findIslandById(islands, id) {
  return islands.find((i) => i.id === id) || null;
}

function findIslandAt(islands, x, y) {
  return islands.find((i) => i.x === x && i.y === y) || null;
}

function nextBridgeValue(curr) {
  if (curr === 0) return 1;
  if (curr === 1) return 2;
  return 0;
}

export default function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const puzzle = PUZZLES[puzzleIndex];
  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedIslandId, setSelectedIslandId] = useState(null);
  const [error, setError] = useState(null);

  const [cursorIslandId, setCursorIslandId] = useState(islands[0]?.id ?? null);
  const [kbdFromId, setKbdFromId] = useState(null);

  const svgRef = useRef(null);

  useEffect(() => {
    setBridges(new Map());
    setSelectedIslandId(null);
    setError(null);
    setCursorIslandId(PUZZLES[puzzleIndex].islands[0]?.id ?? null);
    setKbdFromId(null);
  }, [puzzleIndex]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function clearErrorOnValid() {
    if (error) setError(null);
  }

  function trySetBridge(from, to, nextVal) {
    const key = canonicalKey(from, to);
    const curr = bridges.get(key) || 0;
    const delta = nextVal - curr;
    if (delta === 0) return;

    if (delta > 0) {
      const res = canAddBridge(islands, bridges, from, to, delta);
      if (!res.valid) {
        setError(res.error);
        return;
      }
    }

    setBridges((prev) => {
      const m = new Map(prev);
      if (nextVal === 0) m.delete(key);
      else m.set(key, nextVal);
      return m;
    });
    clearErrorOnValid();
  }

  function toggleBridge(from, to) {
    if (!areAdjacent(islands, from, to)) {
      setError('Cannot connect non-adjacent islands');
      return;
    }
    const key = canonicalKey(from, to);
    const curr = bridges.get(key) || 0;
    const nextVal = nextBridgeValue(curr);
    trySetBridge(from, to, nextVal);
  }

  function onIslandClick(island) {
    if (!selectedIslandId) {
      setSelectedIslandId(island.id);
      return;
    }
    if (selectedIslandId === island.id) {
      return;
    }
    const from = findIslandById(islands, selectedIslandId);
    const to = island;
    if (from && to) toggleBridge(from, to);
    setSelectedIslandId(to.id);
  }

  function onBridgeContextToggle(key) {
    const { x1, y1, x2, y2 } = keyToEndpoints(key);
    const from = findIslandAt(islands, x1, y1);
    const to = findIslandAt(islands, x2, y2);
    if (!from || !to) return;
    const curr = bridges.get(key) || 0;
    const nextVal = nextBridgeValue(curr);
    trySetBridge(from, to, nextVal);
  }

  function moveCursor(dx, dy) {
    const base = kbdFromId ? findIslandById(islands, kbdFromId) : findIslandById(islands, cursorIslandId);
    if (!base) return;

    let x = base.x + dx;
    let y = base.y + dy;
    while (x >= 0 && x <= 100 && y >= 0 && y <= 100) {
      const hit = findIslandAt(islands, x, y);
      if (hit) {
        setCursorIslandId(hit.id);
        return;
      }
      x += dx;
      y += dy;
    }
  }

  useEffect(() => {
    function onKeyDown(e) {
      if (e.key === 'ArrowLeft') {
        e.preventDefault();
        moveCursor(-1, 0);
      } else if (e.key === 'ArrowRight') {
        e.preventDefault();
        moveCursor(1, 0);
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        moveCursor(0, -1);
      } else if (e.key === 'ArrowDown') {
        e.preventDefault();
        moveCursor(0, 1);
      } else if (e.key === 'Enter') {
        e.preventDefault();
        if (!kbdFromId) {
          setKbdFromId(cursorIslandId);
        } else {
          const from = findIslandById(islands, kbdFromId);
          const to = findIslandById(islands, cursorIslandId);
          if (from && to && from.id !== to.id) {
            toggleBridge(from, to);
          }
        }
      } else if (e.key === 'Escape') {
        e.preventDefault();
        setKbdFromId(null);
        setSelectedIslandId(null);
      }
    }
    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [cursorIslandId, kbdFromId, islands, bridges, error]);

  function reset() {
    setBridges(new Map());
    setError(null);
    setSelectedIslandId(null);
    setKbdFromId(null);
  }

  const bridgeLines = [];
  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = keyToEndpoints(key);
    const p1 = { x: x1 * GRID_PX, y: y1 * GRID_PX };
    const p2 = { x: x2 * GRID_PX, y: y2 * GRID_PX };
    const vertical = x1 === x2;
    const offset = 4;
    const stroke = '#00ff66';
    const strokeWidth = 3;
    const common = {
      stroke,
      strokeWidth,
      strokeLinecap: 'round'
    };

    const hitStrokeWidth = 14;
    bridgeLines.push(
      <line
        key={`${key}-hit`}
        x1={p1.x}
        y1={p1.y}
        x2={p2.x}
        y2={p2.y}
        stroke="transparent"
        strokeWidth={hitStrokeWidth}
        onContextMenu={(e) => {
          e.preventDefault();
          onBridgeContextToggle(key);
        }}
        onClick={(e) => {
          if (e.ctrlKey) {
            e.preventDefault();
            onBridgeContextToggle(key);
          }
        }}
      />
    );

    if (n === 1) {
      bridgeLines.push(
        <line key={key} x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} {...common} />
      );
    } else if (n === 2) {
      if (vertical) {
        bridgeLines.push(
          <line
            key={`${key}-a`}
            x1={p1.x - offset}
            y1={p1.y}
            x2={p2.x - offset}
            y2={p2.y}
            {...common}
          />
        );
        bridgeLines.push(
          <line
            key={`${key}-b`}
            x1={p1.x + offset}
            y1={p1.y}
            x2={p2.x + offset}
            y2={p2.y}
            {...common}
          />
        );
      } else {
        bridgeLines.push(
          <line
            key={`${key}-a`}
            x1={p1.x}
            y1={p1.y - offset}
            x2={p2.x}
            y2={p2.y - offset}
            {...common}
          />
        );
        bridgeLines.push(
          <line
            key={`${key}-b`}
            x1={p1.x}
            y1={p1.y + offset}
            x2={p2.x}
            y2={p2.y + offset}
            {...common}
          />
        );
      }
    }
  }

  const cursorIsland = findIslandById(islands, cursorIslandId);
  const cursorPx = cursorIsland ? islandPixel(cursorIsland) : { px: -100, py: -100 };

  return (
    <>
      <div className="hud">
        <label>
          Puzzle:{' '}
          <select value={puzzleIndex} onChange={(e) => setPuzzleIndex(Number(e.target.value))}>
            {PUZZLES.map((p, idx) => (
              <option key={p.label} value={idx}>
                {p.label}
              </option>
            ))}
          </select>
        </label>
        <button onClick={reset}>Reset</button>
        <div style={{ opacity: 0.85 }}>
          Cursor: {cursorIslandId}
          {kbdFromId ? ` | From: ${kbdFromId}` : ''}
          {selectedIslandId ? ` | Mouse: ${selectedIslandId}` : ''}
        </div>
      </div>

      {victory ? <div className="victory-banner">SOLVED!</div> : null}
      {!victory && error ? <div className="error-message">{error}</div> : null}

      <svg
        ref={svgRef}
        className="board"
        width={SVG_W}
        height={SVG_H}
        viewBox={`0 0 ${SVG_W} ${SVG_H}`}
        onContextMenu={(e) => e.preventDefault()}
      >
        <g>{bridgeLines}</g>

        {cursorIsland ? (
          <rect
            x={cursorPx.px - ISLAND_R - 8}
            y={cursorPx.py - ISLAND_R - 8}
            width={(ISLAND_R + 8) * 2}
            height={(ISLAND_R + 8) * 2}
            fill="none"
            stroke="#00ff66"
            strokeWidth={2}
            strokeDasharray="6 4"
          />
        ) : null}

        <g>
          {islands.map((i) => {
            const { px, py } = islandPixel(i);
            const cur = counts.get(i.id) || 0;
            const satisfied = cur === i.value;
            const selected = i.id === selectedIslandId || i.id === kbdFromId;
            return (
              <g
                key={i.id}
                transform={`translate(${px}, ${py})`}
                onClick={() => onIslandClick(i)}
                style={{ cursor: 'pointer' }}
              >
                <circle
                  cx={0}
                  cy={0}
                  r={ISLAND_R}
                  fill="#000"
                  stroke={selected ? '#00ff66' : '#00cc55'}
                  strokeWidth={selected ? 3 : 2}
                />
                <text
                  x={0}
                  y={5}
                  textAnchor="middle"
                  fontSize={14}
                  fill={satisfied ? '#00ff66' : '#00cc55'}
                >
                  {i.value}
                </text>
              </g>
            );
          })}
        </g>
      </svg>
    </>
  );
}
